/**
 * Trending Audio Selector
 * 
 * Helper utility to select trending audio tracks for video compositions.
 * Reads from the manifest generated by fetch-trending-audio.js
 * Falls back to static audio if trending tracks unavailable.
 */

import { promises as fs } from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const TRENDING_DIR = path.join(__dirname, '..', '..', 'public', 'music', 'trending');
const MANIFEST_PATH = path.join(TRENDING_DIR, 'manifest.json');

// Fallback static tracks (existing audio in the project)
const FALLBACK_TRACKS = [
  '/music/background-corporate.mp3',
  '/music/uplifting-motivational.mp3',
  '/music/inspiring-ambient.mp3',
];

/**
 * Load the trending audio manifest
 * @returns {Promise<object|null>} Manifest object or null if unavailable
 */
export async function loadManifest() {
  try {
    const content = await fs.readFile(MANIFEST_PATH, 'utf-8');
    return JSON.parse(content);
  } catch {
    return null;
  }
}

/**
 * Get list of available trending tracks
 * @returns {Promise<Array>} Array of track objects with filename and metadata
 */
export async function getTrendingTracks() {
  const manifest = await loadManifest();
  
  if (!manifest || !manifest.tracks || manifest.tracks.length === 0) {
    return [];
  }

  // Filter to only tracks that were actually downloaded
  return manifest.tracks.filter(track => track.filename !== null);
}

/**
 * Select a trending audio track
 * 
 * @param {object} options Selection options
 * @param {'top'|'random'|'weighted'} options.strategy - Selection strategy
 *   - 'top': Always return the #1 trending track
 *   - 'random': Random selection from available tracks
 *   - 'weighted': Higher-ranked tracks have higher probability
 * @param {number} options.maxRank - Only consider tracks up to this rank (default: all)
 * @returns {Promise<object>} Selected track with path and metadata
 */
export async function selectTrendingAudio(options = {}) {
  const { 
    strategy = 'weighted',
    maxRank = Infinity,
  } = options;

  const tracks = await getTrendingTracks();
  const availableTracks = tracks.filter(t => t.rank <= maxRank);

  // No trending tracks available - use fallback
  if (availableTracks.length === 0) {
    console.warn('[select-trending-audio] No trending tracks available, using fallback');
    const fallbackTrack = FALLBACK_TRACKS[Math.floor(Math.random() * FALLBACK_TRACKS.length)];
    return {
      path: fallbackTrack,
      filename: path.basename(fallbackTrack),
      title: 'Background Music',
      artist: 'Stock Audio',
      rank: null,
      isFallback: true,
      tiktokUrl: null,
    };
  }

  let selected;

  switch (strategy) {
    case 'top':
      // Return the highest-ranked (lowest rank number) track
      selected = availableTracks.reduce((best, track) => 
        track.rank < best.rank ? track : best
      );
      break;

    case 'random':
      // Pure random selection
      selected = availableTracks[Math.floor(Math.random() * availableTracks.length)];
      break;

    case 'weighted':
    default:
      // Weighted random: higher-ranked tracks more likely
      // Weight formula: 1/rank (so rank 1 = weight 1, rank 10 = weight 0.1)
      const totalWeight = availableTracks.reduce((sum, t) => sum + (1 / t.rank), 0);
      let random = Math.random() * totalWeight;
      
      for (const track of availableTracks) {
        random -= (1 / track.rank);
        if (random <= 0) {
          selected = track;
          break;
        }
      }
      
      // Fallback to first if something went wrong
      if (!selected) {
        selected = availableTracks[0];
      }
      break;
  }

  return {
    path: `/music/trending/${selected.filename}`,
    filename: selected.filename,
    title: selected.title,
    artist: selected.artist,
    rank: selected.rank,
    videoCount: selected.videoCount,
    isFallback: false,
    tiktokUrl: selected.tiktokUrl,
  };
}

/**
 * Get a specific trending track by rank
 * @param {number} rank The rank of the track to get (1-based)
 * @returns {Promise<object|null>} Track object or null if not found
 */
export async function getTrendingByRank(rank) {
  const tracks = await getTrendingTracks();
  const track = tracks.find(t => t.rank === rank);
  
  if (!track) {
    return null;
  }

  return {
    path: `/music/trending/${track.filename}`,
    filename: track.filename,
    title: track.title,
    artist: track.artist,
    rank: track.rank,
    videoCount: track.videoCount,
    isFallback: false,
    tiktokUrl: track.tiktokUrl,
  };
}

/**
 * Check if trending audio is available
 * @returns {Promise<boolean>}
 */
export async function hasTrendingAudio() {
  const tracks = await getTrendingTracks();
  return tracks.length > 0;
}

/**
 * Get manifest metadata (last fetched, region, etc.)
 * @returns {Promise<object|null>}
 */
export async function getManifestInfo() {
  const manifest = await loadManifest();
  
  if (!manifest) {
    return null;
  }

  return {
    fetchedAt: manifest.fetchedAt,
    source: manifest.source,
    region: manifest.region,
    status: manifest.status,
    totalTracks: manifest.tracks?.length || 0,
    availableTracks: manifest.tracks?.filter(t => t.filename !== null).length || 0,
  };
}

// CLI usage for testing
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  (async () => {
    console.log('=== Trending Audio Selector Test ===\n');
    
    const info = await getManifestInfo();
    console.log('Manifest Info:', info || 'No manifest found');
    
    const hasAudio = await hasTrendingAudio();
    console.log('\nHas Trending Audio:', hasAudio);
    
    if (hasAudio) {
      console.log('\n--- Selection Tests ---');
      console.log('Top:', await selectTrendingAudio({ strategy: 'top' }));
      console.log('Random:', await selectTrendingAudio({ strategy: 'random' }));
      console.log('Weighted:', await selectTrendingAudio({ strategy: 'weighted' }));
    } else {
      console.log('\n--- Fallback Test ---');
      console.log('Fallback:', await selectTrendingAudio());
    }
  })();
}
